4868       Op1->hasNUses(2) && *ShAmt == Ty->getScalarSizeInBits() - 1 &&
4869       match(Op0, m_OneUse(m_c_Add(m_Specific(A), m_Specific(Op1))))) {
4870     // Op1 = ashr i32 A, 31   ; smear the sign bit
